  p('faq-itr-filing','FAQ','ITR Filing FAQ | Common Questions Answered | WorkIndex','Answers to the most common ITR filing questions in India — which form, due date, documents, refund timeline, and how to hire a CA on WorkIndex.','ITR Filing FAQ','Common questions answered for Indian taxpayers','This FAQ helps taxpayers prepare before filing ITR or hiring a CA, especially around forms, deadlines, documents, refunds and WorkIndex quotes.',[
    { title:'About ITR forms', html:'<h3>Which ITR form is for salaried taxpayers?</h3><p>Eligible simple salary cases may use ITR-1, but capital gains, multiple properties, foreign income or directorship can change the form.</p><h3>Which form is for business income?</h3><p>Business or professional income often requires ITR-3 or ITR-4 depending on books and presumptive eligibility.</p><h3>Which form is for capital gains?</h3><p>Capital gains commonly require ITR-2 or ITR-3 depending on whether business/professional income also exists.</p>' },
    { title:'About deadlines and penalties', html:'<h3>Can I file after the due date?</h3><p>A belated return may be possible within permitted timelines, with late fee and interest impact.</p><h3>Can I revise my ITR?</h3><p>Revision may be possible within the allowed window if the original filing has mistakes.</p>' },
    { title:'About documents', html:'<h3>What documents do I need?</h3><p>PAN, Aadhaar, AIS, Form 26AS, Form 16/16A, bank statements, investment proofs and income-specific records.</p><h3>What is AIS?</h3><p>Annual Information Statement contains broader income and transaction data reported to the income tax department.</p>' },
    { title:'About refunds', html:'<h3>How long does refund take?</h3><p>Refund timelines vary based on processing, bank validation and mismatch checks.</p><h3>My refund is stuck, what should I do?</h3><p>Check e-verification, bank validation, processing status and any outstanding demand.</p>' },
    { title:'About hiring a CA on WorkIndex', html:'<h3>How does WorkIndex help?</h3><p>You post one structured requirement and compare expert responses.</p><h3>What is a fair price?</h3><p>Simple salary ITR is lower cost; capital gains, business income, notices or foreign assets cost more.</p>' }
  ],[{q:'Which ITR form should I file?',a:'It depends on income sources, residential status, business/professional income, capital gains, foreign assets and eligibility conditions.'},{q:'What is the ITR due date?',a:'Due dates vary by taxpayer type and audit applicability. Check the current assessment year deadline before filing.'},{q:'Can I file after July 31?',a:'A belated return may be possible within the permitted period, but late fee and interest can apply.'},{q:'What documents are needed for ITR?',a:'Common records include PAN, Aadhaar, AIS, Form 26AS, Form 16/16A, bank statements and income-specific proofs.'},{q:'How does WorkIndex help with ITR?',a:'WorkIndex lets you post structured requirements and compare CA responses before hiring.'}],['itr-filing-services','itr-filing-cost-india','hire-ca-online-india','faq-hiring-ca-online'],'tax'),

  p('faq-company-registration','FAQ','Company Registration FAQ India | WorkIndex','Common questions about registering a company in India — Pvt Ltd vs LLP vs OPC, MCA process, DSC, DIN, SPICe+, cost and timeline.','Company Registration FAQ India','Pvt Ltd, LLP, OPC, cost and compliance answered','This FAQ helps founders choose a legal structure, prepare MCA documents and understand compliance after incorporation.',[
    { title:'Choosing the right structure', body:'Pvt Ltd suits scalable businesses and investors, LLP suits professional/service firms with flexibility, OPC suits solo founders, and partnership/proprietorship suits simpler early-stage operations with different liability tradeoffs.' },
    { title:'About the registration process', html:'<h3>How long does company registration take?</h3><p>Simple cases can complete in days if name, documents and signatures are ready; resubmissions delay it.</p><h3>What is SPICe+?</h3><p>SPICe+ is MCA’s integrated company incorporation form.</p><h3>What are DSC and DIN?</h3><p>DSC is digital signature; DIN is director identification number.</p>' },
    { title:'About cost', html:'<h3>What is the government fee?</h3><p>Fee depends on structure, capital, state stamp duty and forms.</p><h3>What does a CA/CS charge?</h3><p>Professional fee depends on scope: incorporation only, GST, trademark, agreements and post-registration compliance.</p>' },
    { title:'Compliance after registration', items:['Auditor appointment.','Board and shareholder records.','Annual AOC-4/MGT-7 filings.','Statutory audit for companies.','GST, PF/ESI, PT or TDS registration if applicable.'] },
    { title:'NRI and foreign founders', body:'NRIs and foreign nationals can participate in Indian companies subject to documentation, residency, FEMA and sectoral rules.' }
  ],[{q:'Pvt Ltd or LLP, which is better?',a:'Pvt Ltd suits fundraising and equity; LLP suits flexible professional/service structures.'},{q:'Can I register without office address?',a:'A registered office address proof is needed; rented premises usually require NOC and agreement.'},{q:'Do I need GST immediately?',a:'GST depends on turnover, business model, ecommerce and interstate supplies.'},{q:'Can an NRI be a director?',a:'Yes, with proper documents and compliance; at least one resident director may be required for a company.'},{q:'How do I post on WorkIndex?',a:'Choose company registration, mention structure, founders, state, urgency and add documents available.'}],['business-registration','company-registration-cost','documents-required-for-company-registration','faq-business-registration'],'company')
